// Script Continued Below
// v2.5.13 | 08.08.2020 | STRY0076605:  Sequential Review
(function executeRule(current, previous /*null when async*/) {
	// STRY0105793 - Email Notification when task assignment changes.
	if(current.assigned_to && previous.assigned_to){
		current.previous_assigned_to = previous.assigned_to;
	}
	// STRY0106824 - Close Request(s) when task assignment changes.
	if(previous.assigned_to){
		tcs = new TaskerCommonScriptingMethods();
		var sys_id = current.sys_id;
		//close any open requests from the previous assigned member
		tcs.queryRelated('x_153465_discovert_tasker_requests', 
						[{"parent":sys_id}, {"u_status": "In progress"}, {"u_requested_by": previous.assigned_to}], 
						function(record){
			// set the task values here,  the request record information is updated in the after update business rule
			if(record.u_request_type ==	"Clarification"){
				current.u_clarification_requested = false;
			}
			if(record.u_request_type ==	"Extension"){
				current.extension_requested = false;
				current.extended_suspense_date = null;
			}
			if(record.u_request_type ==	"Reassignment"){
				current.reassignment_requested = false;
			}
		});
	}




	var insertTaskerHelper = new TaskerHelpers();
	var updatedState = insertTaskerHelper.getUpdatedState(current);
	current.state = updatedState;

	if(current.state == 1){
		current.u_last_unassigned_date = null;
		gs.addInfoMessage(current.number + ' has been assigned to ' + current.assigned_to.getDisplayValue());
	}
})(current, previous);
